def count_vowels(word):
    vowels = 'aeiou'
    count = 0
    for char in word.lower():
        if char in vowels:
            count += 1
    return count

result = count_vowels('education')
print(result)  # Output: 5

import csv

try:
    with open('decisions.csv', 'r') as f:
        reader = csv.DictReader(f)
        buys = [row for row in reader if row['side'].upper() == 'BUY']

    totals = {}
    for row in buys:
        asset = row['asset']
        cost = float(row['qty']) * float(row['price'])
        totals[asset] = totals.get(asset, 0) + cost

    with open('summary.txt', 'w') as f:
        f.write('Buy Summary\n')
        f.write('=' * 30 + '\n')
        for asset, total in totals.items():
            f.write(f'{asset}: ${total:.2f}\n')

    print('Summary written to summary.txt')

except FileNotFoundError:
    print('Error: decisions.csv not found')
except csv.Error as e:
    print(f'CSV error: {e}')
